import{_ as t,c as l,o as i,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const k=JSON.parse('{"title":"v1.1.3：Bedrock 增强 + 桌面版 CLI 安装","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.3.md","filePath":"changelog/v1.1.3.md","lastUpdated":1772014034000}'),d={name:"changelog/v1.1.3.md"};function o(h,e,n,s,c,b){return i(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-1-3-bedrock-增强-桌面版-cli-安装" tabindex="-1">v1.1.3：Bedrock 增强 + 桌面版 CLI 安装 <a class="header-anchor" href="#v1-1-3-bedrock-增强-桌面版-cli-安装" aria-label="Permalink to “v1.1.3：Bedrock 增强 + 桌面版 CLI 安装”">​</a></h1><p><strong>发布日期</strong>：2026年1月5日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新增强了 <strong>Amazon Bedrock 支持</strong>，桌面版可以<strong>一键安装 CLI</strong>，还修复了多个稳定性问题。</p><hr><h2 id="新功能-bedrock-配置增强" tabindex="-1">新功能：Bedrock 配置增强 <a class="header-anchor" href="#新功能-bedrock-配置增强" aria-label="Permalink to “新功能：Bedrock 配置增强”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>Amazon Bedrock 用户现在有更多配置选项：</p><ul><li>支持 <strong>jp. 前缀</strong>的跨区域推理配置</li><li>更清晰的<strong>认证优先级</strong></li><li>更灵活的配置方式</li></ul><h3 id="认证优先级" tabindex="-1">认证优先级 <a class="header-anchor" href="#认证优先级" aria-label="Permalink to “认证优先级”">​</a></h3><ol><li>配置文件中的 API Key</li><li>环境变量</li><li>AWS CLI 配置</li><li>IAM 角色</li></ol><p>👉 <strong>相关教程</strong>：<a href="/appendix/providers.html">模型提供商</a></p><hr><h2 id="桌面版-一键安装-cli" tabindex="-1">桌面版：一键安装 CLI <a class="header-anchor" href="#桌面版-一键安装-cli" aria-label="Permalink to “桌面版：一键安装 CLI”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>桌面版现在可以<strong>一键安装命令行工具</strong>，不用单独下载安装了。</p><h3 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to “如何使用？”">​</a></h3><ol><li>打开桌面版设置</li><li>找到「安装 CLI」选项</li><li>点击安装</li></ol><p>安装后就可以在终端使用 <code>opencode</code> 命令了。</p><hr><h2 id="改进-权限配置顺序保留" tabindex="-1">改进：权限配置顺序保留 <a class="header-anchor" href="#改进-权限配置顺序保留" aria-label="Permalink to “改进：权限配置顺序保留”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>在配置权限规则时，规则的顺序可能会被打乱，导致优先级不符合预期。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>现在会<strong>保留你定义的顺序</strong>，第一条规则优先级最高。</p><hr><h2 id="改进-自定义命令支持图片" tabindex="-1">改进：自定义命令支持图片 <a class="header-anchor" href="#改进-自定义命令支持图片" aria-label="Permalink to “改进：自定义命令支持图片”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>使用自定义命令（Custom Commands）时，无法传递图片参数。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>现在可以在自定义命令中使用图片了，比如截图分析、图片处理等场景。</p><hr><h2 id="改进-tab-展开目录" tabindex="-1">改进：Tab 展开目录 <a class="header-anchor" href="#改进-tab-展开目录" aria-label="Permalink to “改进：Tab 展开目录”">​</a></h2><h3 id="之前的问题-2" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-2" aria-label="Permalink to “之前的问题”">​</a></h3><p>在文件自动补全中，按 Tab 和 Enter 的行为不够直观。</p><h3 id="现在的情况-2" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-2" aria-label="Permalink to “现在的情况”">​</a></h3><ul><li><strong>Tab</strong>：展开目录，查看子文件</li><li><strong>Enter</strong>：选中当前项</li></ul><p>更符合直觉的操作方式。</p><hr><h2 id="桌面版改进" tabindex="-1">桌面版改进 <a class="header-anchor" href="#桌面版改进" aria-label="Permalink to “桌面版改进”">​</a></h2><table tabindex="0"><thead><tr><th>改进</th><th>说明</th></tr></thead><tbody><tr><td>图片附件存储</td><td>图片现在会正确保存</td></tr><tr><td>底部内边距修复</td><td>内容不再被遮挡</td></tr><tr><td>终端稳定性</td><td>修复了终端闪烁问题</td></tr><tr><td>事件批处理</td><td>提升整体性能</td></tr><tr><td>输入框不再遮挡内容</td><td>长对话时滚动更顺畅</td></tr><tr><td>Worktree 导航修复</td><td>选择 worktree 后正确跳转</td></tr><tr><td>IME 输入修复</td><td>中文输入法不再误触发提交</td></tr><tr><td>项目折叠高亮</td><td>折叠的活动项目会高亮显示</td></tr></tbody></table><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用 Amazon Bedrock</td><td>✅ 升级</td></tr><tr><td>使用桌面版</td><td>✅ 升级</td></tr><tr><td>使用中文输入法</td><td>✅ 升级，修复了 IME 问题</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',46),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>修复终端长时间运行进程</li><li>保留权限配置键顺序，维持用户定义的优先级</li><li>自定义命令支持传递图片（@melihmucuk）</li><li>支持 Amazon Bedrock 跨区域推理的 jp. 前缀（@ikeda-tomoya-swx）</li><li>Bedrock 配置选项和认证优先级（@wnkz）</li><li>Transform agent 改进和优化</li><li>过滤空消息和 reasoning 以兼容 Anthropic API</li></ul><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>Tab 展开目录，Enter 选中（@yuguorui）</li><li>更新 GitHub Actions 示例使用 actions/checkout@v6（@joshuadavidthomas）</li><li>修复 Lucent Orange 主题斜杠命令背景透明度（@roerohan）</li><li>文档添加 MCP 命令说明（@cravenceiling）</li><li>添加系统主题解析和事件处理</li><li>改进操作中断时的体验</li></ul><h3 id="desktop-桌面版" tabindex="-1">Desktop（桌面版） <a class="header-anchor" href="#desktop-桌面版" aria-label="Permalink to “Desktop（桌面版）”">​</a></h3><ul><li>存储图片附件</li><li>修复底部内边距</li><li>修复终端闪烁问题</li><li>事件批处理提升性能</li><li>修复输入框遮挡内容</li><li>Worktree 选择后正确导航</li><li>避免 IME 输入时误提交（@MogamiTsuchikawa）</li><li>折叠的活动项目高亮显示（@albingroen）</li><li>修复项目折叠/展开时的闪烁和导航问题（@albingroen）</li><li>添加 CLI 安装功能（@dbpolito）</li><li>修复项目编辑对话框中的图片拖拽（@albingroen）</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><p>感谢 10 位社区贡献者！</p></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const m=t(d,[["render",o]]);export{k as __pageData,m as default};
